package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testPrintAndEscape() throws IOException {
        // Given
        CSVFormat csvFormat = new CSVFormat(',', '"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);
        CSVFormat spyFormat = spy(csvFormat);
        CharSequence value = "abc,def";
        int offset = 0;
        int len = value.length();
        StringWriter out = new StringWriter();

        // When
        spyFormat.printAndEscape(value, offset, len, out);

        // Then
        assertEquals("abc\",\"def", out.toString());
    }

    // Add more test cases for different scenarios if needed

}
